#!/usr/bin/env bun
// Auto-generated by Stackpanel — do not edit manually.
// Docker entrypoint: loads SOPS-encrypted env, then spawns the application.

import { spawn } from "node:child_process";
import { loadAppEnv } from "./node-loader";

const env = { ...process.env };

const appName = env.APP_NAME || "web";
const rawEnv = env.APP_ENV || env.NODE_ENV || "prod";
const appEnv = rawEnv === "production" ? "prod" : rawEnv === "development" ? "dev" : rawEnv;

// Load and inject SOPS-encrypted environment variables
await loadAppEnv(appName, appEnv);

// If running a Next.js web server, prerender pages first
const command = process.argv.slice(2).join(" ");
if (command.endsWith("next start") || command.endsWith("bun run start")) {
  await exec("bunx next build --experimental-build-mode generate");
}

// Launch application
await exec(command);

function exec(cmd: string): Promise<void> {
  const child = spawn(cmd, { shell: true, stdio: "inherit", env: process.env });
  return new Promise((resolve, reject) => {
    child.on("exit", (code) => {
      if (code === 0) {
        resolve();
      } else {
        reject(new Error(`${cmd} failed rc=${code}`));
      }
    });
  });
}
